require __DIR__.'/config.php';if(!function_exists('date_display')){function date_display(?string $value):string{$value=trim((string)$value);if($value==='')return '';try{return(new DateTimeImmutable($value,new DateTimeZone('Europe/Istanbul')))->format('d.m.Y');}catch(Throwable){return '';}}function date_input_to_storage(?string $value):?string{$value=trim((string)$value);if($value==='')return null;foreach(['!d.m.Y','!Y-m-d','!Y-m-d\TH:i'] as $format){$date=DateTimeImmutable::createFromFormat($format,$value,new DateTimeZone('Europe/Istanbul'));$errors=DateTimeImmutable::getLastErrors();if($date&&($errors===false||($errors['warning_count']===0&&$errors['error_count']===0)))return $date->format('Y-m-d');}return null;}}require_login();$id=(int)($_GET['id']??$_POST['id']??0);$stmt=db()->prepare('SELECT * FROM items WHERE id=?');$stmt->execute([$id]);$item=$stmt->fetch();if(!$item){http_response_code(404);exit('Kayıt bulunamadı.');}$error='';
$locations=db()->query('SELECT name FROM location_definitions WHERE active=1 ORDER BY sort_order,name')->fetchAll();if(!in_array('Oda',array_column($locations,'name'),true))$locations[]=['name'=>'Oda'];$roomNumbers=db()->query('SELECT room_number FROM room_definitions WHERE active=1 ORDER BY CAST(room_number AS INTEGER)')->fetchAll(PDO::FETCH_COLUMN);$departments=db()->query('SELECT name FROM department_definitions WHERE active=1 ORDER BY sort_order,name')->fetchAll();$storages=db()->query('SELECT name FROM storage_definitions WHERE active=1 ORDER BY sort_order,name')->fetchAll();$itemDefinitions=db()->query('SELECT id,category,name FROM item_definitions WHERE active=1 ORDER BY sort_order,category,name')->fetchAll();$statuses=['Eşleşme bekliyor','Talep sahibinden eylem bekliyor','Yetkilendirilmiş kişi bekleniyor','Teslim edildi','Teslim edildi (Görüşüldü)','Depoda','Kargolandı','Tasfiye edildi'];
$currentDefinition=null;foreach($itemDefinitions as $definition)if($definition['category']===$item['category']&&$definition['name']===$item['name']){$currentDefinition=(string)$definition['id'];break;}$definitionValue=$_POST['item_definition']??($currentDefinition??'current');
if($_SERVER['REQUEST_METHOD']==='POST'){
 verify_csrf();$foundAt=date_input_to_storage($_POST['found_at']??'');$deliveredAt=date_input_to_storage($_POST['delivered_at']??'');$locationValue=trim($_POST['location']??'');$roomNumber=trim($_POST['room_number']??'');if($locationValue==='Oda'){$locationValue=$roomNumber;if(!preg_match('/^\d{3,4}$/',$roomNumber))$error='Oda numarası 3 veya 4 rakam olmalıdır.';elseif(!in_array($roomNumber,$roomNumbers,true))$error='Bu oda numarası daha önce kaydedilmemiş. Listeden mevcut bir oda numarası seçin.';}foreach(['item_no','found_at','location','found_department','item_definition','storage_location','status'] as $key)if(trim($_POST[$key]??'')==='')$error='Zorunlu alanları doldurun.';if(!$foundAt||(trim($_POST['delivered_at']??'')!==''&&!$deliveredAt))$error='Tarihleri gg.aa.yyyy biçiminde girin.';
 $category=$item['category'];$name=$item['name'];if(!$error&&$_POST['item_definition']!=='current'){$s=db()->prepare('SELECT category,name FROM item_definitions WHERE id=? AND active=1');$s->execute([(int)$_POST['item_definition']]);$selected=$s->fetch();if(!$selected)$error='Geçerli bir eşya seçin.';else{$category=$selected['category'];$name=$selected['name'];}}
 if(!$error){$sql='UPDATE items SET item_no=?,serial_no=?,related_items=?,found_at=?,location=?,found_department=?,found_by=?,quantity=?,category=?,name=?,brand=?,color=?,details=?,storage_location=?,status=?,delivered_at=?,delivery_method=?,delivered_by=?,delivery_form_no=?,recorded_by=? WHERE id=?';$values=[trim($_POST['item_no']),trim($_POST['serial_no']??''),trim($_POST['related_items']??''),$foundAt,$locationValue,trim($_POST['found_department']),trim($_POST['found_by']??''),max(1,(int)($_POST['quantity']??1)),$category,$name,trim($_POST['brand']??''),trim($_POST['color']??''),trim($_POST['details']??''),trim($_POST['storage_location']),trim($_POST['status']),$deliveredAt,trim($_POST['delivery_method']??''),trim($_POST['delivered_by']??''),trim($_POST['delivery_form_no']??''),$_SESSION['user']['name'],$id];try{$stmt=db()->prepare($sql);$stmt->execute($values);redirect('index.php');}catch(PDOException $e){$error='Kayıt güncellenemedi. Eşya numarası benzersiz olmalıdır.';}}
}
function field(string $key):string{return e($_POST[$key]??$GLOBALS['item'][$key]??'');}
function chosen(string $value,string $current):string{return $value===$current?'selected':'';}
